1	// Edge function: manage-social-link (US-035)
2	//
3	// Contract:
4	//   POST add:    { action: 'add', platform: 'tiktok'|'instagram', handle: string }
5	//     → 200 { social_link_id: string, metrics_status: { tiktok?: Status, ig_details?: Status, ig_posts?: Status } }
6	//       where Status is 'fresh' | 'refreshing' | 'failed'.
7	//   POST unlink: { action: 'unlink', social_link_id: string }
8	//     → 200 { ok: true }
9	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
10	//     → 401 { error: 'UNAUTHORIZED' }
11	//     → 403 { error: 'FORBIDDEN' }
12	//     → 404 { error: 'LINK_NOT_FOUND' }
13	//     → 409 { error: 'ALREADY_LINKED' | 'HANDLE_TAKEN' }
14	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
15	//
16	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
17	//       _shared/jwt.ts and asserts role='creator'. Deployed with
18	//       verify_jwt=false at the gateway; the handler enforces auth.
19	//
20	// Atomicity: single INSERT (add) or single UPDATE (unlink) inside the
21	// public.manage_social_link RPC's implicit transaction.
22	//
23	// Apify dispatch: on a successful add, the function kicks the Apify runs
24	// for the freshly-added handle via _shared/apify-dispatch.ts (one
25	// tiktok_profile run for TikTok; ig_details + ig_posts for Instagram).
26	// The per-platform outcome is reported in metrics_status so the client
27	// can render 'refreshing' placeholders or surface a 'failed' state.
28	// A dispatch failure does NOT roll back the social_links row.
29	
30	import { createClient } from "npm:@supabase/supabase-js@2";
31	import { verifyJwt } from "../_shared/jwt.ts";
32	import { corsHeaders } from "../_shared/cors.ts";
33	import { dispatchApifyForLinks } from "../_shared/apify-dispatch.ts";
34	
35	const UUID_RE =
36	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
37	const HANDLE_RE = /^[a-zA-Z0-9_.]{1,30}$/;
38	
39	type Platform = "tiktok" | "instagram";
40	
41	interface AddRequest {
42	  action?: "add";
43	  platform?: unknown;
44	  handle?: unknown;
45	}
46	interface UnlinkRequest {
47	  action?: "unlink";
48	  social_link_id?: unknown;
49	}
50	type AnyRequest = AddRequest | UnlinkRequest | { action?: unknown };
51	
52	function jsonResponse(status: number, body: unknown): Response {
53	  return new Response(JSON.stringify(body), {
54	    status,
55	    headers: { ...corsHeaders, "Content-Type": "application/json" },
56	  });
57	}
58	
59	function bearerToken(req: Request): string | null {
60	  const raw = req.headers.get("Authorization") ??
61	    req.headers.get("authorization");
62	  if (!raw) return null;
63	  const m = raw.match(/^Bearer\s+(.+)$/i);
64	  return m ? m[1].trim() : null;
65	}
66	
67	function normalizeHandle(value: unknown): string | null {
68	  if (typeof value !== "string") return null;
69	  const stripped = value.trim().replace(/^@+/, "").trim();
70	  if (stripped.length === 0 || !HANDLE_RE.test(stripped)) return null;
71	  return stripped;
72	}
73	
74	function parsePlatform(value: unknown): Platform | null {
75	  return value === "tiktok" || value === "instagram" ? value : null;
76	}
77	
78	Deno.serve(async (req) => {
79	  if (req.method === "OPTIONS") {
80	    return new Response(null, { status: 204, headers: corsHeaders });
81	  }
82	  if (req.method !== "POST") {
83	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
84	  }
85	
86	  const token = bearerToken(req);
87	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
88	
89	  let claims;
90	  try {
91	    claims = await verifyJwt(token);
92	  } catch {
93	    return jsonResponse(401, { error: "UNAUTHORIZED" });
94	  }
95	  if (claims.app_role !== "creator") {
96	    return jsonResponse(403, { error: "FORBIDDEN" });
97	  }
98	
99	  let body: AnyRequest;
100	  try {
101	    body = await req.json();
102	  } catch {
103	    return jsonResponse(400, { error: "INVALID_JSON" });
104	  }
105	
106	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
107	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
108	  if (!supabaseUrl || !serviceRoleKey) {
109	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
110	  }
111	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
112	    auth: { persistSession: false, autoRefreshToken: false },
113	  });
114	
115	  if (body.action === "add") {
116	    const platform = parsePlatform((body as AddRequest).platform);
117	    const handle = normalizeHandle((body as AddRequest).handle);
118	    if (!platform || !handle) {
119	      return jsonResponse(400, { error: "INVALID_REQUEST" });
120	    }
121	    const { data, error } = await supabase.rpc("manage_social_link", {
122	      p_user_id: claims.sub,
123	      p_action: "add",
124	      p_platform: platform,
125	      p_handle: handle,
126	      p_social_link_id: null,
127	    });
128	    if (error) {
129	      console.error("manage_social_link add rpc error", error);
130	      return jsonResponse(500, { error: "DB_ERROR" });
131	    }
132	    const result = data as
133	      | { social_link_id?: string; error?: string }
134	      | null;
135	    if (result?.error === "ALREADY_LINKED") {
136	      return jsonResponse(409, { error: "ALREADY_LINKED" });
137	    }
138	    if (result?.error === "HANDLE_TAKEN") {
139	      return jsonResponse(409, { error: "HANDLE_TAKEN" });
140	    }
141	    if (result?.error === "INVALID_REQUEST") {
142	      return jsonResponse(400, { error: "INVALID_REQUEST" });
143	    }
144	    if (!result?.social_link_id) {
145	      console.error("manage_social_link add returned unexpected shape", result);
146	      return jsonResponse(500, { error: "DB_ERROR" });
147	    }
148	    const metricsStatus = await dispatchApifyForLinks({
149	      supabaseUrl,
150	      links: [{ linkId: result.social_link_id, platform, handle }],
151	    });
152	    return jsonResponse(200, {
153	      social_link_id: result.social_link_id,
154	      metrics_status: metricsStatus,
155	    });
156	  }
157	
158	  if (body.action === "unlink") {
159	    const socialLinkId =
160	      typeof (body as UnlinkRequest).social_link_id === "string" &&
161	        UUID_RE.test((body as UnlinkRequest).social_link_id as string)
162	        ? ((body as UnlinkRequest).social_link_id as string)
163	        : null;
164	    if (!socialLinkId) {
165	      return jsonResponse(400, { error: "INVALID_REQUEST" });
166	    }
167	    const { data, error } = await supabase.rpc("manage_social_link", {
168	      p_user_id: claims.sub,
169	      p_action: "unlink",
170	      p_platform: null,
171	      p_handle: null,
172	      p_social_link_id: socialLinkId,
173	    });
174	    if (error) {
175	      console.error("manage_social_link unlink rpc error", error);
176	      return jsonResponse(500, { error: "DB_ERROR" });
177	    }
178	    const result = data as { ok?: boolean; error?: string } | null;
179	    if (result?.error === "LINK_NOT_FOUND") {
180	      return jsonResponse(404, { error: "LINK_NOT_FOUND" });
181	    }
182	    if (result?.error === "INVALID_REQUEST") {
183	      return jsonResponse(400, { error: "INVALID_REQUEST" });
184	    }
185	    if (!result?.ok) {
186	      console.error(
187	        "manage_social_link unlink returned unexpected shape",
188	        result,
189	      );
190	      return jsonResponse(500, { error: "DB_ERROR" });
191	    }
192	    return jsonResponse(200, { ok: true });
193	  }
194	
195	  return jsonResponse(400, { error: "INVALID_REQUEST" });
196	});
