1	// Edge function: auth-signup-creator (US-019 + US-020)
2	//
3	// Contract:
4	//   POST { username: string, tiktok_handle?: string, instagram_handle?: string }
5	//     → 200 {
6	//         token: string,
7	//         user_id: string,
8	//         role: 'creator',
9	//         metrics_status: { tiktok?: Status, ig_details?: Status, ig_posts?: Status },
10	//       }
11	//       where Status is 'fresh' | 'refreshing' | 'failed'.
12	//     → 400 { error: 'INVALID_REQUEST' | 'INVALID_JSON' }
13	//     → 422 { error: 'HANDLE_REQUIRED' }
14	//     → 409 { error: 'USERNAME_TAKEN' | 'HANDLE_TAKEN' }
15	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'JWT_ERROR' }
16	//
17	// Auth: none. This is how a creator obtains their first JWT, so the
18	// endpoint is verify_jwt=false at the gateway. The handler itself mints
19	// the token via _shared/jwt.ts (HS256, MARKETIFY_JWT_SECRET).
20	//
21	// Atomicity: the users + creator_profiles + social_links inserts run
22	// inside a single Postgres transaction via the public.auth_signup_creator
23	// RPC (us_019 migration). A failure on any insert rolls back the flow.
24	// Apify dispatch happens AFTER the RPC commits — per spec §5.1, a
25	// dispatch failure does NOT roll back the account (the user gets their
26	// JWT, metrics_status carries the per-platform outcome so the client can
27	// decide whether to retry later or surface a 'refreshing' placeholder).
28	//
29	// Handle normalization: leading '@' is stripped and whitespace trimmed
30	// before the RPC call. Handles are compared case-insensitively (citext),
31	// matching social_links.handle's column type.
32	//
33	// Apify dispatch (US-020): once the RPC commits, we look up the
34	// freshly-inserted social_links rows, then kick one or more Apify runs in
35	// parallel via Promise.allSettled — tiktok_profile for TikTok handles;
36	// ig_details and ig_posts for Instagram handles. Each run is registered
37	// with a per-run webhook pointing back at /functions/v1/apify-webhook so
38	// the receiver can persist the metric_snapshots row when Apify finishes.
39	// The wait window is APIFY_WAIT_SECS (60s); runs that come back
40	// SUCCEEDED within the window are reported as 'fresh' (the webhook will
41	// also arrive and be deduped via the unique index on run_id), otherwise
42	// 'refreshing' and the client polls. A thrown dispatch is 'failed'.
43	//
44	// Pre-refreshing rows: the spec calls for pre-creating metric_snapshots
45	// rows in status='refreshing' before the scrape so the client has
46	// something to read. That's deferred — the existing US-016..US-018 RPCs
47	// INSERT on webhook arrival via ON CONFLICT DO NOTHING, so the row
48	// appears only once Apify finishes. Tracked as a spec gap in progress.txt.
49	//
50	// Rate limit: not implemented yet. Spec §5.1 requires per-IP throttling
51	// via a signup_attempts table (does not yet exist). Same status as the
52	// sibling auth-signup-lister — tracked in progress.txt Codebase Patterns.
53	
54	import { createClient, type SupabaseClient } from "npm:@supabase/supabase-js@2";
55	import { signJwt } from "../_shared/jwt.ts";
56	import { corsHeaders } from "../_shared/cors.ts";
57	import {
58	  type ApifyDispatchLink,
59	  dispatchApifyForLinks,
60	  type MetricsKey,
61	  type MetricsStatus,
62	} from "../_shared/apify-dispatch.ts";
63	
64	interface SignupRequest {
65	  username?: unknown;
66	  tiktok_handle?: unknown;
67	  instagram_handle?: unknown;
68	}
69	
70	function jsonResponse(status: number, body: unknown): Response {
71	  return new Response(JSON.stringify(body), {
72	    status,
73	    headers: { ...corsHeaders, "Content-Type": "application/json" },
74	  });
75	}
76	
77	function isString(value: unknown): value is string {
78	  return typeof value === "string";
79	}
80	
81	function normalizeHandle(value: unknown): string | null {
82	  if (!isString(value)) return null;
83	  const stripped = value.trim().replace(/^@+/, "").trim();
84	  return stripped.length > 0 ? stripped : null;
85	}
86	
87	Deno.serve(async (req) => {
88	  if (req.method === "OPTIONS") {
89	    return new Response(null, { status: 204, headers: corsHeaders });
90	  }
91	  if (req.method !== "POST") {
92	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
93	  }
94	
95	  let body: SignupRequest;
96	  try {
97	    body = await req.json();
98	  } catch {
99	    return jsonResponse(400, { error: "INVALID_JSON" });
100	  }
101	
102	  const username =
103	    isString(body.username) && body.username.trim().length > 0
104	      ? body.username.trim()
105	      : null;
106	  const tiktokHandle = normalizeHandle(body.tiktok_handle);
107	  const instagramHandle = normalizeHandle(body.instagram_handle);
108	
109	  if (!username) {
110	    return jsonResponse(400, { error: "INVALID_REQUEST" });
111	  }
112	  if (!tiktokHandle && !instagramHandle) {
113	    return jsonResponse(422, { error: "HANDLE_REQUIRED" });
114	  }
115	
116	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
117	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
118	  if (!supabaseUrl || !serviceRoleKey) {
119	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
120	  }
121	
122	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
123	    auth: { persistSession: false, autoRefreshToken: false },
124	  });
125	
126	  const { data, error } = await supabase.rpc("auth_signup_creator", {
127	    p_username: username,
128	    p_tiktok_handle: tiktokHandle,
129	    p_instagram_handle: instagramHandle,
130	  });
131	
132	  if (error) {
133	    console.error("auth_signup_creator rpc error", error);
134	    return jsonResponse(500, { error: "DB_ERROR" });
135	  }
136	
137	  const result = data as { user_id?: string; error?: string } | null;
138	  if (result?.error === "USERNAME_TAKEN") {
139	    return jsonResponse(409, { error: "USERNAME_TAKEN" });
140	  }
141	  if (result?.error === "HANDLE_TAKEN") {
142	    return jsonResponse(409, { error: "HANDLE_TAKEN" });
143	  }
144	  if (!result?.user_id) {
145	    console.error("auth_signup_creator returned unexpected shape", result);
146	    return jsonResponse(500, { error: "DB_ERROR" });
147	  }
148	
149	  const userId = result.user_id;
150	  const sessionId = crypto.randomUUID();
151	  let token: string;
152	  try {
153	    token = await signJwt({
154	      sub: userId,
155	      app_role: "creator",
156	      session_id: sessionId,
157	    });
158	  } catch (err) {
159	    console.error("signJwt failed", err);
160	    return jsonResponse(500, { error: "JWT_ERROR" });
161	  }
162	
163	  const metricsStatus = await dispatchApifyRuns({
164	    supabase,
165	    supabaseUrl,
166	    userId,
167	    tiktokHandle,
168	    instagramHandle,
169	  });
170	
171	  return jsonResponse(200, {
172	    token,
173	    user_id: userId,
174	    role: "creator",
175	    metrics_status: metricsStatus,
176	  });
177	});
178	
179	// Dispatches the Apify runs required for the freshly-created creator
180	// account. Returns a partial metrics_status map keyed by platform. If
181	// APIFY_KEY or APIFY_WEBHOOK_SECRET is unset (e.g. local dev without
182	// Apify credentials), logs a warning and returns {} — the account is
183	// still usable, the client just won't see any metrics until a future
184	// scrape picks it up. A failure to dispatch a single platform does not
185	// affect the others.
186	// deno-lint-ignore no-explicit-any -- supabase-js generic args differ between
187	// the createClient call above (inferred as public schema) and any helper
188	// import; typing this parameter loosely avoids a widening mismatch.
189	async function dispatchApifyRuns(params: {
190	  supabase: SupabaseClient<any, any, any>;
191	  supabaseUrl: string;
192	  userId: string;
193	  tiktokHandle: string | null;
194	  instagramHandle: string | null;
195	}): Promise<Partial<Record<MetricsKey, MetricsStatus>>> {
196	  const { supabase, supabaseUrl, userId } = params;
197	
198	  const apifyKey = Deno.env.get("APIFY_KEY");
199	  const webhookSecret = Deno.env.get("APIFY_WEBHOOK_SECRET");
200	  if (!apifyKey || !webhookSecret) {
201	    console.warn(
202	      "apify dispatch skipped: APIFY_KEY or APIFY_WEBHOOK_SECRET missing",
203	    );
204	    return {};
205	  }
206	
207	  const { data: links, error: linksError } = await supabase
208	    .from("social_links")
209	    .select("id,platform,handle")
210	    .eq("user_id", userId);
211	  if (linksError) {
212	    console.error("social_links lookup failed", linksError);
213	    return {};
214	  }
215	
216	  const linkRows = (links ?? []) as Array<
217	    { id: string; platform: string; handle: string }
218	  >;
219	  const dispatchLinks: ApifyDispatchLink[] = linkRows
220	    .filter((l) => l.platform === "tiktok" || l.platform === "instagram")
221	    .map((l) => ({
222	      linkId: l.id,
223	      platform: l.platform as "tiktok" | "instagram",
224	      handle: l.handle,
225	    }));
226	
227	  return await dispatchApifyForLinks({ supabaseUrl, links: dispatchLinks });
228	}
