107	function jsonResponse(status: number, body: unknown): Response {
108	  return new Response(JSON.stringify(body), {
109	    status,
110	    headers: { ...corsHeaders, "Content-Type": "application/json" },
111	  });
112	}
113	
114	function isNonEmptyString(value: unknown): value is string {
115	  return typeof value === "string" && value.length > 0;
116	}
117	
118	// Constant-time string compare. Lengths are compared first; when lengths
119	// differ we still iterate over the longer string to keep timing flat.
120	function timingSafeEqual(a: string, b: string): boolean {
121	  const enc = new TextEncoder();
122	  const aBytes = enc.encode(a);
123	  const bBytes = enc.encode(b);
124	  const len = Math.max(aBytes.length, bBytes.length);
125	  let diff = aBytes.length ^ bBytes.length;
126	  for (let i = 0; i < len; i++) {
127	    const ac = i < aBytes.length ? aBytes[i] : 0;
128	    const bc = i < bBytes.length ? bBytes[i] : 0;
129	    diff |= ac ^ bc;
130	  }
131	  return diff === 0;
132	}
133	
134	function verifyWebhookSecret(req: Request): boolean {
135	  const provided = req.headers.get("x-apify-webhook-secret");
136	  if (!isNonEmptyString(provided)) return false;
137	  const current = Deno.env.get("APIFY_WEBHOOK_SECRET") ?? "";
138	  const previous = Deno.env.get("APIFY_WEBHOOK_SECRET_PREVIOUS") ?? "";
139	  if (!current && !previous) return false;
140	  // Both comparisons always run (no short-circuit) so an attacker who has
141	  // recovered `current` can't time-distinguish whether `previous` is set.
142	  const matchCurrent = current ? timingSafeEqual(provided, current) : false;
143	  const matchPrevious = previous ? timingSafeEqual(provided, previous) : false;
144	  return matchCurrent || matchPrevious;
145	}
