193	async function fetchDatasetItems(
194	  datasetId: string,
195	  apifyKey: string,
196	): Promise<unknown[]> {
197	  const url = new URL(`${APIFY_API_BASE}/datasets/${datasetId}/items`);
198	  url.searchParams.set("token", apifyKey);
199	  url.searchParams.set("clean", "1");
200	  const res = await fetch(url.toString(), { method: "GET" });
201	  if (!res.ok) {
202	    // Don't include res body — Apify can echo the token-carrying URL inside
203	    // error payloads, and this lands in edge-function logs.
204	    throw new Error(
205	      `Apify dataset '${datasetId}' fetch failed: ${res.status} ${res.statusText}`,
206	    );
207	  }
208	  const items = await res.json();
209	  if (!Array.isArray(items)) {
210	    throw new Error(`Apify dataset '${datasetId}' returned non-array payload`);
211	  }
212	  return items;
213	}
214	
215	Deno.serve(async (req) => {
216	  if (req.method === "OPTIONS") {
217	    return new Response(null, { status: 204, headers: corsHeaders });
218	  }
219	  if (req.method !== "POST") {
220	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
221	  }
222	
223	  if (!verifyWebhookSecret(req)) {
224	    return jsonResponse(401, { error: "UNAUTHORIZED" });
225	  }
226	
227	  let body: WebhookBody;
228	  try {
229	    body = await req.json();
230	  } catch {
231	    return jsonResponse(400, { error: "INVALID_JSON" });
232	  }
233	
234	  if (
235	    !isNonEmptyString(body.eventType) ||
236	    !TERMINAL_EVENT_TYPES.has(body.eventType) ||
237	    !validResource(body.resource) ||
238	    !isNonEmptyString(body.social_link_id) ||
239	    !isNonEmptyString(body.scrape_mode) ||
240	    !isNonEmptyString(body.run_id)
241	  ) {
242	    return jsonResponse(400, { error: "INVALID_REQUEST" });
243	  }
244	
245	  const scrapeMode = body.scrape_mode as ScrapeMode;
246	  if (
247	    scrapeMode !== "tiktok_profile" &&
248	    scrapeMode !== "ig_details" &&
249	    scrapeMode !== "ig_posts"
250	  ) {
251	    // Unknown scrape_mode: return 200 so Apify does not retry. The row stays
252	    // 'refreshing' until the fail-stuck-refreshing cron janitor
253	    // (docs/tech-architecture.md §15) flips it to 'failed'.
254	    return jsonResponse(200, { ok: true, skipped: "unsupported_scrape_mode" });
255	  }
256	
257	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
258	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
259	  if (!supabaseUrl || !serviceRoleKey) {
260	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
261	  }
262	
263	  const resource = body.resource as ApifyResource;
264	  const runId = body.run_id;
265	  const socialLinkId = body.social_link_id;
266	  const fetchedAt = isNonEmptyString(body.apify_finished_at)
267	    ? body.apify_finished_at
268	    : new Date().toISOString();
269	
270	  let nextStatus: MetricStatus;
271	  let items: unknown[] | null = null;
272	  let rawPayload: unknown = null;
273	  let errorMessage: string | null = null;
274	
275	  if (body.eventType === SUCCEEDED_EVENT) {
276	    const apifyKey = Deno.env.get("APIFY_KEY");
277	    if (!apifyKey) {
278	      return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
279	    }
280	    try {
281	      items = await fetchDatasetItems(resource.defaultDatasetId, apifyKey);
282	    } catch (err) {
283	      console.error("apify dataset fetch failed", {
284	        run_id: runId,
285	        dataset_id: resource.defaultDatasetId,
286	        error: err instanceof Error ? err.message : String(err),
287	      });
288	      return jsonResponse(500, { error: "APIFY_FETCH_ERROR" });
289	    }
290	    rawPayload = items;
291	    nextStatus = "fresh";
292	  } else {
293	    nextStatus = "failed";
294	    errorMessage = `apify_${body.eventType.toLowerCase().replace(/\./g, "_")}`;
295	    rawPayload = { resource, eventType: body.eventType };
296	  }
297	
298	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
299	    auth: { persistSession: false, autoRefreshToken: false },
300	  });
301	
302	  // Single source of truth for the RPC name per branch — used both as the
303	  // .rpc() call argument and in the error-log context, so the two stay in
304	  // sync if either side is renamed.
305	  const rpcName = scrapeMode === "tiktok_profile"
306	    ? "apify_webhook_persist_tiktok_profile"
307	    : scrapeMode === "ig_details"
308	    ? "apify_webhook_persist_ig_details"
309	    : "apify_webhook_persist_ig_posts";
310	
311	  let result: PersistResult | null = null;
312	  let rpcError: { code?: string; message?: string } | null = null;
313	
314	  if (scrapeMode === "tiktok_profile") {
315	    let followerCount: number | null = null;
316	    let followingCount: number | null = null;
317	    let totalLikes: number | null = null;
318	    let videoCount: number | null = null;
319	    let avgViewsLast10: number | null = null;
320	    let isVerified: boolean | null = null;
321	    if (items) {
322	      const tiktokItems = items as TikTokItem[];
323	      const first = tiktokItems[0];
324	      const authorMeta = first?.authorMeta;
325	      if (authorMeta) {
326	        followerCount = typeof authorMeta.fans === "number" ? authorMeta.fans : null;
327	        followingCount = typeof authorMeta.following === "number"
328	          ? authorMeta.following
329	          : null;
330	        totalLikes = typeof authorMeta.heart === "number" ? authorMeta.heart : null;
331	        videoCount = typeof authorMeta.video === "number" ? authorMeta.video : null;
332	        isVerified = typeof authorMeta.verified === "boolean"
333	          ? authorMeta.verified
334	          : null;
335	      }
336	      avgViewsLast10 = meanPlayCount(tiktokItems);
337	    }
338	    const { data, error } = await supabase.rpc(
339	      rpcName,
340	      {
341	        p_run_id: runId,
342	        p_social_link_id: socialLinkId,
343	        p_status: nextStatus,
344	        p_fetched_at: fetchedAt,
345	        p_follower_count: followerCount,
346	        p_following_count: followingCount,
347	        p_total_likes: totalLikes,
348	        p_video_count: videoCount,
349	        p_avg_views_last_10: avgViewsLast10,
350	        p_is_verified: isVerified,
351	        p_raw_payload: rawPayload as never,
352	        p_error_message: errorMessage,
353	      },
354	    );
355	    result = data as PersistResult | null;
356	    rpcError = error;
357	  } else if (scrapeMode === "ig_details") {
358	    // ig_details — details[0] yields follower/following/posts/verified per
359	    // docs/tech-architecture.md §3c. avg_views_last_10 is owned by ig_posts,
360	    // so leave it NULL here; the denorm trigger for ig_details updates only
361	    // instagram_follower_count + instagram_media_count + metrics_fetched_at.
362	    let followerCount: number | null = null;
363	    let followingCount: number | null = null;
364	    let mediaCount: number | null = null;
365	    let isVerified: boolean | null = null;
366	    if (items) {
367	      const igItems = items as InstagramDetailsItem[];
368	      const first = igItems[0];
369	      if (first) {
370	        followerCount = typeof first.followersCount === "number"
371	          ? first.followersCount
372	          : null;
373	        followingCount = typeof first.followsCount === "number"
374	          ? first.followsCount
375	          : null;
376	        mediaCount = typeof first.postsCount === "number"
377	          ? first.postsCount
378	          : null;
379	        isVerified = typeof first.verified === "boolean"
380	          ? first.verified
381	          : null;
382	      }
383	    }
384	    const { data, error } = await supabase.rpc(
385	      rpcName,
386	      {
387	        p_run_id: runId,
388	        p_social_link_id: socialLinkId,
389	        p_status: nextStatus,
390	        p_fetched_at: fetchedAt,
391	        p_follower_count: followerCount,
392	        p_following_count: followingCount,
393	        p_media_count: mediaCount,
394	        p_is_verified: isVerified,
395	        p_raw_payload: rawPayload as never,
396	        p_error_message: errorMessage,
397	      },
398	    );
399	    result = data as PersistResult | null;
400	    rpcError = error;
401	  } else {
402	    // ig_posts — only avg_views_last_10 is owned here (spec §4.7
403	    // column-ownership comments). The denorm trigger for ig_posts mirrors
404	    // this single value into creator_profiles.instagram_avg_views_last_10
405	    // and bumps metrics_fetched_at.
406	    let avgViewsLast10: number | null = null;
407	    if (items) {
408	      avgViewsLast10 = meanInstagramVideoViews(items as InstagramPostItem[]);
409	    }
410	    const { data, error } = await supabase.rpc(
411	      rpcName,
412	      {
413	        p_run_id: runId,
414	        p_social_link_id: socialLinkId,
415	        p_status: nextStatus,
416	        p_fetched_at: fetchedAt,
417	        p_avg_views_last_10: avgViewsLast10,
418	        p_raw_payload: rawPayload as never,
419	        p_error_message: errorMessage,
420	      },
421	    );
422	    result = data as PersistResult | null;
423	    rpcError = error;
424	  }
425	
426	  if (rpcError) {
427	    console.error(`${rpcName} rpc error`, {
428	      run_id: runId,
429	      code: rpcError.code,
430	      message: rpcError.message,
431	    });
432	    return jsonResponse(500, { error: "DB_ERROR" });
433	  }
434	
435	  return jsonResponse(200, {
436	    ok: true,
437	    inserted: result?.inserted === true,
438	    duplicate: result?.duplicate === true,
439	  });
440	});
